525	static int gettime(void)
526	{
527		static struct timeval first;
528		static int once = 1;
529		struct timeval now;
530		if (once)
531		{
532			gettimeofday(&first, NULL);
533			once = 0;
534		}
535		gettimeofday(&now, NULL);
536		return (now.tv_sec - first.tv_sec) * 1000 + (now.tv_usec - first.tv_usec) / 1000;
537	}
