539	static int has_percent_d(char *s)
540	{
541		/* find '%[0-9]*d' */
542		while (*s)
543		{
544			if (*s++ == '%')
545			{
546				while (*s >= '0' && *s <= '9')
547					++s;
548				if (*s == 'd')
549					return 1;
550			}
551		}
552		return 0;
553	}
