555	/* Output file level (as opposed to page level) headers */
556	static void
557	file_level_headers(fz_context *ctx)
558	{
559		if (output_format == OUT_STEXT_XML || output_format == OUT_TRACE || output_format == OUT_BBOX || output_format == OUT_OCR_STEXT_XML || output_format == OUT_XMLTEXT)
560			fz_write_printf(ctx, out, "<?xml version=\"1.0\"?>\n");
561	
562		if (output_format == OUT_HTML || output_format == OUT_OCR_HTML)
563			fz_print_stext_header_as_html(ctx, out);
564		if (output_format == OUT_XHTML || output_format == OUT_OCR_XHTML)
565			fz_print_stext_header_as_xhtml(ctx, out);
566	
567		if (output_format == OUT_STEXT_XML || output_format == OUT_TRACE || output_format == OUT_BBOX || output_format == OUT_OCR_STEXT_XML)
568			fz_write_printf(ctx, out, "<document filename=\"%s\">\n", filename);
569		if (output_format == OUT_STEXT_JSON || output_format == OUT_OCR_STEXT_JSON)
570			fz_write_printf(ctx, out, "{%q:%q,%q:[", "file", filename, "pages");
571	
572		if (output_format == OUT_PS)
573			fz_write_ps_file_header(ctx, out);
574	
575		if (output_format == OUT_PWG)
576			fz_write_pwg_file_header(ctx, out);
577	
