632	static void apply_kill_switch(fz_device *dev)
633	{
634		if (s_kill == 1)
635		{
636			/* kill all non-clipping text operators */
637			dev->fill_text = NULL;
638			dev->stroke_text = NULL;
639			dev->ignore_text = NULL;
640		}
641		else if (s_kill == 2)
642		{
643			/* kill all non-clipping path, image, and shading operators */
644			dev->fill_path = NULL;
645			dev->stroke_path = NULL;
646			dev->fill_shade = NULL;
647			dev->fill_image = NULL;
648			dev->fill_image_mask = NULL;
649		}
650	}
