1000			tbounds = fz_transform_rect(mediabox, ctm);
1001	
1002			fz_try(ctx)
1003			{
1004				fz_svg_device_options opts;
1005				memset(&opts, 0, sizeof opts);
1006				opts.text_format = FZ_SVG_TEXT_AS_PATH;
1007				opts.reuse_images = 1;
