1029			{
1030				fz_rethrow(ctx);
1031			}
1032		}
1033		else
1034		{
1035			float zoom;
1036			fz_matrix ctm;
1037			fz_rect tbounds;
1038			fz_irect ibounds;
1039			fz_pixmap *pix = NULL;
1040			int w, h;
1041			fz_bitmap *bit = NULL;
