1051			ibounds = fz_round_rect(tbounds);
1052	
1053			/* Make local copies of our width/height */
1054			w = width;
1055			h = height;
1056	
1057			/* If a resolution is specified, check to see whether w/h are
1058			 * exceeded; if not, unset them. */
1059			if (res_specified)
1060			{
1061				int t;
1062				t = ibounds.x1 - ibounds.x0;
1063				if (w && t <= w)
