1068			}
1069	
1070			/* Now w or h will be 0 unless they need to be enforced. */
1071			if (w || h)
1072			{
1073				float scalex = w / (tbounds.x1 - tbounds.x0);
1074				float scaley = h / (tbounds.y1 - tbounds.y0);
1075				fz_matrix scale_mat;
1076	
1077				if (fit)
1078				{
1079					if (w == 0)
1080						scalex = 1.0f;
1081					if (h == 0)
1082						scaley = 1.0f;
1083				}
1084				else
1085				{
1086					if (w == 0)
1087						scalex = scaley;
1088					if (h == 0)
1089						scaley = scalex;
1090				}
1091				if (!fit)
1092				{
1093					if (scalex > scaley)
1094						scalex = scaley;
1095					else
1096						scaley = scalex;
1097				}
1098				scale_mat = fz_scale(scalex, scaley);
1099				ctm = fz_concat(ctm, scale_mat);
1100				tbounds = fz_transform_rect(mediabox, ctm);
1101			}
1102			ibounds = fz_round_rect(tbounds);
1103			tbounds = fz_rect_from_irect(ibounds);
1104	
1105			fz_try(ctx)
1106			{
1107				fz_irect band_ibounds = ibounds;
