1109				int totalheight = ibounds.y1 - ibounds.y0;
1110				int drawheight = totalheight;
1111	
1112				if (band_height != 0)
1113				{
1114					/* Banded rendering; we'll only render to a
1115					 * given height at a time. */
1116					drawheight = band_height;
1117					if (totalheight > band_height)
1118						band_ibounds.y1 = band_ibounds.y0 + band_height;
1119					bands = (totalheight + band_height-1)/band_height;
1120					tbounds.y1 = tbounds.y0 + band_height + 2;
1121					DEBUG_THREADS(("Using %d Bands\n", bands));
1122				}
1123	
1124	#ifndef DISABLE_MUTHREADS
1125				if (num_workers < bands && max_num_workers >= bands)
1126				{
1127					int i;
1128					int fail = 0;
1129					for (i = num_workers; i < fz_mini(bands, max_num_workers); ++i)
1130					{
1131						workers[i].ctx = fz_clone_context(ctx);
1132						workers[i].num = i;
1133						fail |= mu_create_semaphore(&workers[i].start);
1134						fail |= mu_create_semaphore(&workers[i].stop);
1135						printf("create worker_thread %d\n", i);
1136						fail |= mu_create_thread(&workers[i].thread, worker_thread, &workers[i]);
1137						if (!fail)
1138							num_workers++;
1139					}
1140					if (fail)
1141					{
1142						fprintf(stderr, "worker startup failed\n");
1143						exit(1);
1144					}
1145				}
1146	
1147				if (num_workers > 0)
1148				{
1149					for (band = 0; band < fz_mini(num_workers, bands); band++)
1150					{
1151						workers[band].band = band;
1152						workers[band].error = 0;
1153						workers[band].ctm = ctm;
1154						workers[band].tbounds = tbounds;
1155						tbounds.y0 += band_height;
1156						tbounds.y1 += band_height;
1157						memset(&workers[band].cookie, 0, sizeof(fz_cookie));
1158						workers[band].list = list;
1159						workers[band].pix = fz_new_pixmap_with_bbox(ctx, colorspace, band_ibounds, seps, alpha);
1160						workers[band].pix->y += band * band_height;
1161						fz_set_pixmap_resolution(ctx, workers[band].pix, resolution, resolution);
1162						workers[band].running = 1;
1163						DEBUG_THREADS(("Worker %d, Pre-triggering band %d\n", band, band));
1164						mu_trigger_semaphore(&workers[band].start);
1165					}
1166					pix = workers[0].pix;
1167				}
1168				else
1169	#endif
1170				{
1171					pix = fz_new_pixmap_with_bbox(ctx, colorspace, band_ibounds, seps, alpha);
1172					fz_set_pixmap_resolution(ctx, pix, resolution, resolution);
1173				}
1174	
1175				assert(pix != NULL); /* Reassure Coverity that there there must be a pix */
1176	
1177				/* Output any page level headers (for banded formats) */
1178				if (output_format != OUT_NONE)
1179				{
1180					if (output_format == OUT_PGM || output_format == OUT_PPM || output_format == OUT_PNM)
1181						bander = fz_new_pnm_band_writer(ctx, out_);
1182					else if (output_format == OUT_PAM)
1183						bander = fz_new_pam_band_writer(ctx, out_);
1184					else if (output_format == OUT_PNG)
1185						bander = fz_new_png_band_writer(ctx, out_);
1186					else if (output_format == OUT_PBM)
1187						bander = fz_new_pbm_band_writer(ctx, out_);
1188					else if (output_format == OUT_PKM)
1189						bander = fz_new_pkm_band_writer(ctx, out_);
1190					else if (output_format == OUT_PS)
1191						bander = fz_new_ps_band_writer(ctx, out_);
1192					else if (output_format == OUT_PSD)
1193						bander = fz_new_psd_band_writer(ctx, out_);
1194					else if (output_format == OUT_PWG)
1195					{
1196						fz_pwg_options opts;
1197						fz_init_pwg_options(ctx, &opts);
1198						fz_apply_pwg_options(ctx, &opts, user_options);
1199						if (out_cs == CS_MONO)
1200							bander = fz_new_mono_pwg_band_writer(ctx, out_, &opts);
1201						else
1202							bander = fz_new_pwg_band_writer(ctx, out_, &opts);
1203					}
1204					else if (output_format == OUT_PCL)
1205					{
1206						fz_pcl_options opts;
1207						fz_init_pcl_options(ctx, &opts);
1208						fz_apply_pcl_options(ctx, &opts, user_options);
1209						if (out_cs == CS_MONO)
1210							bander = fz_new_mono_pcl_band_writer(ctx, out_, &opts);
1211						else
1212							bander = fz_new_color_pcl_band_writer(ctx, out_, &opts);
1213					}
1214					if (bander)
1215					{
1216						fz_write_header(ctx, bander, pix->w, totalheight, pix->n, pix->alpha, pix->xres, pix->yres, output_pagenum++, pix->colorspace, pix->seps);
1217					}
1218				}
1219				if (output_format == OUT_J2K && bands > 1)
1220				{
1221					fz_throw(ctx, FZ_ERROR_ARGUMENT, "Can't band with J2k output!");
1222				}
1223	
1224				for (band = 0; band < bands; band++)
1225				{
1226					if (num_workers > 0)
1227					{
1228						worker_t *work = &workers[band % num_workers];
1229	#ifndef DISABLE_MUTHREADS
1230						DEBUG_THREADS(("Waiting for worker %d to complete band %d\n", work->num, band));
1231						mu_wait_semaphore(&work->stop);
1232	#endif
1233						work->running = 0;
1234						cookie->errors += work->cookie.errors;
1235						pix = work->pix;
1236						bit = work->bit;
1237						work->bit = NULL;
1238	
1239						if (work->error)
1240							fz_throw(ctx, FZ_ERROR_GENERIC, "worker %d failed to render band %d", work->num, band);
1241					}
1242					else
1243						drawband(ctx, page, list, ctm, tbounds, cookie, band * band_height, pix, &bit);
1244	
1245					if (output_format != OUT_NONE)
1246					{
1247						if (bander && (pix || bit))
1248							fz_write_band(ctx, bander, bit ? bit->stride : pix->stride, drawheight, bit ? bit->samples : pix->samples);
1249	#if FZ_ENABLE_JPX
1250						if (output_format == OUT_J2K)
1251						{
1252							fz_write_pixmap_as_jpx(ctx, out_, pix, 80);
1253						}
1254	#else
1255						fz_throw(ctx, FZ_ERROR_GENERIC, "JPX support disabled");
1256	#endif
1257						fz_drop_bitmap(ctx, bit);
1258						bit = NULL;
1259					}
1260	
1261					if (num_workers > 0 && band + num_workers < bands)
1262					{
1263						worker_t *work = &workers[band % num_workers];
1264						work->band = band + num_workers;
1265						work->pix->y = band_ibounds.y0 + work->band * band_height;
1266						work->ctm = ctm;
1267						work->tbounds = tbounds;
1268						memset(&work->cookie, 0, sizeof(fz_cookie));
1269						work->running = 1;
1270	#ifndef DISABLE_MUTHREADS
1271						DEBUG_THREADS(("Triggering worker %d for band %d\n", work->num, work->band));
1272						mu_trigger_semaphore(&work->start);
1273	#endif
1274					}
1275					if (num_workers <= 0)
1276						pix->y += band_height;
1277					tbounds.y0 += band_height;
1278					tbounds.y1 += band_height;
1279				}
1280	
1281				if (output_format != OUT_PCLM && output_format != OUT_OCR_PDF)
1282					fz_close_band_writer(ctx, bander);
1283	
1284				/* FIXME */
1285				if (showmd5 && pix)
1286				{
1287					unsigned char digest[16];
1288					int i;
1289	
1290					fz_md5_pixmap(ctx, pix, digest);
1291					fprintf(stderr, " ");
1292					for (i = 0; i < 16; i++)
1293						fprintf(stderr, "%02x", digest[i]);
1294				}
1295			}
1296			fz_always(ctx)
1297			{
1298				if (output_format != OUT_PCLM && output_format != OUT_OCR_PDF)
1299				{
1300					fz_drop_band_writer(ctx, bander);
1301					/* bander must be set to NULL to avoid use-after-frees. A use-after-free
1302					 * would occur when a valid page was followed by a page with invalid
1303					 * pixmap dimensions, causing bander -- a static -- to point to previously
1304					 * freed memory instead of a new band_writer. */
1305					bander = NULL;
1306				}
1307				fz_drop_bitmap(ctx, bit);
1308				bit = NULL;
1309				if (num_workers > 0)
1310				{
1311					int i;
1312					DEBUG_THREADS(("Stopping workers and removing their pixmaps\n"));
1313					for (i = 0; i < num_workers; i++)
1314					{
1315						if (workers[i].running)
1316						{
1317	#ifndef DISABLE_MUTHREADS
1318							DEBUG_THREADS(("Waiting on worker %d to finish processing\n", i));
1319							mu_wait_semaphore(&workers[i].stop);
1320	#endif
1321							workers[i].running = 0;
1322						}
1323						else
1324							DEBUG_THREADS(("Worker %d not processing anything\n", i));
1325						fz_drop_pixmap(ctx, workers[i].pix);
1326						workers[i].pix = NULL;
1327					}
1328				}
1329				else
1330					fz_drop_pixmap(ctx, pix);
1331			}
1332			fz_catch(ctx)
1333			{
1334				if (output_format == OUT_PCLM || output_format == OUT_OCR_PDF)
1335				{
1336					fz_drop_band_writer(ctx, bander);
1337					bander = NULL;
1338				}
1339				fz_rethrow(ctx);
1340			}
1341		}
1342	
1343		if (output_file_per_page)
1344			file_level_trailers(ctx);
1345	
1346		if (showtime)
1347		{
1348			int end = gettime();
1349			int diff = end - start;
1350	
1351			if (bg)
1352			{
1353				if (diff + interptime < timing.min)
1354				{
1355					timing.min = diff + interptime;
1356					timing.mininterp = interptime;
1357					timing.minpage = pagenum;
1358					timing.minfilename = fname;
1359				}
1360				if (diff + interptime > timing.max)
1361				{
1362					timing.max = diff + interptime;
1363					timing.maxinterp = interptime;
1364					timing.maxpage = pagenum;
1365					timing.maxfilename = fname;
1366				}
1367				timing.count ++;
1368	
1369				fprintf(stderr, " %dms (interpretation) %dms (rendering) %dms (total)", interptime, diff, diff + interptime);
1370			}
1371			else
1372			{
1373				if (diff < timing.min)
1374				{
1375					timing.min = diff;
1376					timing.minpage = pagenum;
1377					timing.minfilename = fname;
1378				}
1379				if (diff > timing.max)
1380				{
1381					timing.max = diff;
1382					timing.maxpage = pagenum;
1383					timing.maxfilename = fname;
1384				}
1385				timing.total += diff;
1386				timing.count ++;
1387	
1388				fprintf(stderr, " %dms", diff);
1389			}
1390		}
1391	
1392		if (!quiet || showfeatures || showtime || showmd5)
1393			fprintf(stderr, "\n");
1394	
1395		if (lowmemory)
1396			fz_empty_store(ctx);
1397	
1398		if (showmemory)
1399			fz_dump_glyph_cache_stats(ctx, fz_stderr(ctx));
1400	
1401		fz_flush_warnings(ctx);
1402	
1403		if (cookie->errors)
1404			errored = 1;
1405	}
