1407	static void bgprint_flush(void)
1408	{
1409		if (!bgprint.active || !bgprint.started)
1410			return;
1411	
1412	#ifndef DISABLE_MUTHREADS
1413		mu_wait_semaphore(&bgprint.stop);
1414	#endif
1415		bgprint.started = 0;
1416	}
