1418	static void drawpage(fz_context *ctx, fz_document *doc, int pagenum)
1419	{
1420		fz_page *page = NULL;
1421		fz_display_list *list = NULL;
1422		fz_device *dev = NULL;
1423		int start;
1424		fz_cookie cookie = { 0 };
1425		fz_separations *seps = NULL;
1426		const char *features = "";
1427		char output_path[512];
1428	
1429		fz_var(list);
1430		fz_var(dev);
1431		fz_var(seps);
1432		fz_var(page);
1433	
1434		start = (showtime ? gettime() : 0);
1435	
1436		if (output_file_per_page)
1437		{
1438			bgprint_flush();
1439	
1440			fz_format_output_path(ctx, output_path, sizeof output_path, output, pagenum);
1441	
1442	#if FZ_ENABLE_PDF
1443			if (output_format == OUT_PDF)
1444				pdfout = pdf_create_document(ctx);
1445			else
1446	#endif
1447				out = fz_new_output_with_path(ctx, output_path, 0);
1448		}
1449	
1450		fz_try(ctx)
1451		{
1452			page = fz_load_page(ctx, doc, pagenum - 1);
1453	
1454			if (spots != SPOTS_NONE)
1455			{
1456				seps = fz_page_separations(ctx, page);
1457				if (seps)
1458				{
1459					int i, n = fz_count_separations(ctx, seps);
1460					if (spots == SPOTS_FULL)
1461						for (i = 0; i < n; i++)
1462							fz_set_separation_behavior(ctx, seps, i, FZ_SEPARATION_SPOT);
1463					else
1464						for (i = 0; i < n; i++)
1465							fz_set_separation_behavior(ctx, seps, i, FZ_SEPARATION_COMPOSITE);
1466				}
1467				else if (fz_page_uses_overprint(ctx, page))
1468				{
1469					/* This page uses overprint, so we need an empty
1470					 * sep object to force the overprint simulation on. */
1471					seps = fz_new_separations(ctx, 0);
1472				}
1473				else if (oi && fz_colorspace_n(ctx, oi) != fz_colorspace_n(ctx, colorspace))
1474				{
1475					/* We have an output intent, and it's incompatible
1476					 * with the colorspace our device needs. Force the
1477					 * overprint simulation on, because this ensures that
1478					 * we 'simulate' the output intent too. */
1479					seps = fz_new_separations(ctx, 0);
1480				}
1481			}
1482	
1483			if (uselist)
1484			{
1485				list = fz_new_display_list(ctx, fz_bound_page_box(ctx, page, page_box));
1486				dev = fz_new_list_device(ctx, list);
1487				if (lowmemory)
1488					fz_enable_device_hints(ctx, dev, FZ_NO_CACHE);
1489				fz_run_page(ctx, page, dev, fz_identity, &cookie);
1490				fz_close_device(ctx, dev);
1491	
1492				if (bgprint.active && showtime)
1493				{
1494					int end = gettime();
1495					start = end - start;
1496				}
1497			}
1498	
1499			if (showfeatures)
1500			{
1501				int iscolor;
1502				dev = fz_new_test_device(ctx, &iscolor, 0.02f, 0, NULL);
1503				apply_kill_switch(dev);
1504				if (lowmemory)
1505					fz_enable_device_hints(ctx, dev, FZ_NO_CACHE);
1506				if (list)
1507					fz_run_display_list(ctx, list, dev, fz_identity, fz_infinite_rect, NULL);
1508				else
1509					fz_run_page(ctx, page, dev, fz_identity, &cookie);
1510				fz_close_device(ctx, dev);
1511				features = iscolor ? " color" : " grayscale";
1512			}
1513	
1514			if (bgprint.active)
1515			{
1516				bgprint_flush();
1517				if (bgprint.error)
1518				{
1519					/* it failed, do not continue trying */
1520					bgprint.active = 0;
1521				}
1522				else if (bgprint.active)
1523				{
1524					if (!quiet || showfeatures || showtime || showmd5)
1525						fprintf(stderr, "page %s %d%s", filename, pagenum, features);
1526	
1527					/* hand page, list, seps and possibly (pdf) output over to thread for rendering */
1528					bgprint.started = 1;
1529					bgprint.page = page;
1530					page = NULL;
1531					bgprint.list = list;
1532					list = NULL;
1533					bgprint.seps = seps;
1534					seps = NULL;
1535					bgprint.filename = filename;
1536					bgprint.pagenum = pagenum;
1537					bgprint.interptime = start;
1538					bgprint.error = 0;
1539					if (output_file_per_page)
1540					{
1541	#if FZ_ENABLE_PDF
1542						if (output_format == OUT_PDF)
1543						{
1544							bgprint.pdfout_path = fz_strdup(ctx, output_path);
1545							bgprint.pdfout = pdfout;
1546							pdfout = NULL;
1547						}
1548						else
1549	#endif
1550						{
1551							bgprint.out = out;
1552							out = NULL;
1553						}
1554					}
1555	#ifndef DISABLE_MUTHREADS
1556					mu_trigger_semaphore(&bgprint.start);
1557	#endif
1558				}
1559			}
1560			else
1561			{
1562				void *localpdfout = NULL;
1563	#if FZ_ENABLE_PDF
1564				localpdfout = pdfout;
1565	#endif
1566				if (!quiet || showfeatures || showtime || showmd5)
1567					fprintf(stderr, "page %s %d%s", filename, pagenum, features);
1568				dodrawpage(ctx, page, list, pagenum, &cookie, start, 0, filename, 0, seps, localpdfout, out);
1569			}
1570	
1571			if (output_file_per_page)
1572			{
1573	#if FZ_ENABLE_PDF
1574				if (output_format == OUT_PDF && pdfout)
1575					pdf_save_document(ctx, pdfout, output_path, NULL);
1576				else
1577	#endif
1578				if (out)
1579					fz_close_output(ctx, out);
1580			}
1581		}
1582		fz_always(ctx)
1583		{
1584			fz_drop_device(ctx, dev);
1585			fz_drop_display_list(ctx, list);
1586			fz_drop_separations(ctx, seps);
1587			fz_drop_page(ctx, page);
1588			if (output_file_per_page)
1589			{
1590	#if FZ_ENABLE_PDF
1591				if (output_format == OUT_PDF && pdfout)
1592				{
1593					pdf_drop_document(ctx, pdfout);
1594					pdfout = NULL;
1595				}
1596				else
1597	#endif
1598				if (out)
1599				{
1600					fz_drop_output(ctx, out);
1601					out = NULL;
1602				}
1603			}
1604		}
1605		fz_catch(ctx)
1606			fz_rethrow(ctx);
1607	}
