1609	static void drawrange(fz_context *ctx, fz_document *doc, const char *range)
1610	{
1611		int page, spage, epage, pagecount;
1612	
1613		pagecount = fz_count_pages(ctx, doc);
1614	
1615		while ((range = fz_parse_page_range(ctx, range, &spage, &epage, pagecount)))
1616		{
1617			if (spage < epage)
1618				for (page = spage; page <= epage; page++)
1619				{
1620					fz_try(ctx)
1621						drawpage(ctx, doc, page);
1622					fz_catch(ctx)
1623					{
1624						if (ignore_errors)
1625						{
1626							fz_report_error(ctx);
1627							fz_warn(ctx, "ignoring error on page %d in '%s'", page, filename);
1628						}
1629						else
1630							fz_rethrow(ctx);
1631					}
1632				}
1633			else
1634				for (page = spage; page >= epage; page--)
1635				{
1636					fz_try(ctx)
1637						drawpage(ctx, doc, page);
1638					fz_catch(ctx)
1639					{
1640						if (ignore_errors)
1641						{
1642							fz_report_error(ctx);
1643							fz_warn(ctx, "ignoring error on page %d in '%s'", page, filename);
1644						}
1645						else
1646							fz_rethrow(ctx);
1647					}
1648				}
1649		}
1650	}
