1652	static int
1653	parse_colorspace(const char *name)
1654	{
1655		int i;
1656	
1657		for (i = 0; i < (int)nelem(cs_name_table); i++)
1658		{
1659			if (!strcmp(name, cs_name_table[i].name))
1660				return cs_name_table[i].colorspace;
1661		}
1662	
1663		/* Assume ICC. We will error out later if not the case. */
1664		icc_filename = name;
1665		return CS_ICC;
1666	}
