1668	typedef struct
1669	{
1670		size_t size;
1671	#if defined(_M_IA64) || defined(_M_AMD64)
1672		size_t align;
1673	#endif
1674	} trace_header;
1675	
1676	typedef struct
1677	{
1678		size_t current;
1679		size_t peak;
1680		size_t total;
1681		size_t allocs;
1682		size_t mem_limit;
1683		size_t alloc_limit;
1684	} trace_info;
1685	
1686	static void *hit_limit(void *val)
1687	{
1688		return val;
1689	}
1690	
1691	static void *hit_memory_limit(trace_info *info, int is_malloc, size_t oldsize, size_t size)
1692	{
1693		if (is_malloc)
1694			printf("Memory limit (%zu) hit upon malloc(%zu) when %zu already allocated.\n", info->mem_limit, size, info->current);
1695		else
1696			printf("Memory limit (%zu) hit upon realloc(%zu) from %zu bytes when %zu already allocated.\n", info->mem_limit, size, oldsize, info->current);
1697		return hit_limit(NULL);
1698	}
1699	
1700	
1701	static void *hit_alloc_limit(trace_info *info, int is_malloc, size_t oldsize, size_t size)
1702	{
1703		if (is_malloc)
1704			printf("Allocation limit (%zu) hit upon malloc(%zu) when %zu already allocated.\n", info->alloc_limit, size, info->current);
1705		else
1706			printf("Allocation limit (%zu) hit upon realloc(%zu) from %zu bytes when %zu already allocated.\n", info->alloc_limit, size, oldsize, info->current);
1707		return hit_limit(NULL);
1708	}
1709	
1710	static void *
1711	trace_malloc(void *arg, size_t size)
1712	{
1713		trace_info *info = (trace_info *) arg;
1714		trace_header *p;
1715		if (size == 0)
1716			return NULL;
1717		if (size > SIZE_MAX - sizeof(trace_header))
1718			return NULL;
1719		if (info->mem_limit > 0 && size > info->mem_limit - info->current)
1720			return hit_memory_limit(info, 1, 0, size);
1721		if (info->alloc_limit > 0 && info->allocs > info->alloc_limit)
1722			return hit_alloc_limit(info, 1, 0, size);
1723		p = malloc(size + sizeof(trace_header));
1724		if (p == NULL)
1725			return NULL;
1726		p[0].size = size;
1727		info->current += size;
1728		info->total += size;
1729		if (info->current > info->peak)
1730			info->peak = info->current;
1731		info->allocs++;
1732		return (void *)&p[1];
1733	}
1734	
1735	static void
1736	trace_free(void *arg, void *p_)
1737	{
1738		trace_info *info = (trace_info *) arg;
1739		trace_header *p = (trace_header *)p_;
1740	
1741		if (p == NULL)
1742			return;
1743		info->current -= p[-1].size;
1744		free(&p[-1]);
1745	}
1746	
1747	static void *
1748	trace_realloc(void *arg, void *p_, size_t size)
1749	{
1750		trace_info *info = (trace_info *) arg;
1751		trace_header *p = (trace_header *)p_;
1752		size_t oldsize;
1753	
1754		if (size == 0)
1755		{
1756			trace_free(arg, p_);
1757			return NULL;
1758		}
1759		if (p == NULL)
1760			return trace_malloc(arg, size);
1761		if (size > SIZE_MAX - sizeof(trace_header))
1762			return NULL;
1763		oldsize = p[-1].size;
1764		if (info->mem_limit > 0 && size > info->mem_limit - info->current + oldsize)
1765			return hit_memory_limit(info, 0, oldsize, size);
1766		if (info->alloc_limit > 0 && info->allocs > info->alloc_limit)
1767			return hit_alloc_limit(info, 0, oldsize, size);
1768		p = realloc(&p[-1], size + sizeof(trace_header));
1769		if (p == NULL)
1770			return NULL;
1771		info->current += size - oldsize;
1772		if (size > oldsize)
1773			info->total += size - oldsize;
1774		if (info->current > info->peak)
1775			info->peak = info->current;
1776		p[0].size = size;
1777		info->allocs++;
1778		return &p[1];
1779	}
