1925	static void apply_layer_config(fz_context *ctx, fz_document *doc, const char *lc)
1926	{
1927	#if FZ_ENABLE_PDF
1928		pdf_document *pdoc = pdf_specifics(ctx, doc);
1929		const char *name, *creator;
1930		int config;
1931		int n, j;
1932	
1933		if (!pdoc)
1934		{
1935			fz_warn(ctx, "Only PDF files have layers");
1936			return;
1937		}
1938	
1939		while (iswhite(*lc))
1940			lc++;
1941	
1942		if (*lc == 0 || *lc == 'l')
1943		{
1944			int num_configs = pdf_count_layer_configs(ctx, pdoc);
1945	
1946			fprintf(stderr, "Layer configs:\n");
1947			for (config = 0; config < num_configs; config++)
1948			{
1949				fprintf(stderr, " %s%d:", config < 10 ? " " : "", config);
1950				name = pdf_layer_config_name(ctx, pdoc, config);
1951				if (name)
1952					fprintf(stderr, " Name=\"%s\"", name);
1953				creator = pdf_layer_config_creator(ctx, pdoc, config);
1954				if (creator)
1955					fprintf(stderr, " Creator=\"%s\"", creator);
1956				fprintf(stderr, "\n");
1957			}
1958			return;
1959		}
1960	
1961		/* Read the config number */
1962		if (*lc < '0' || *lc > '9')
1963		{
1964			fprintf(stderr, "cannot find number expected for -y\n");
1965			return;
1966		}
1967		config = fz_atoi(lc);
1968		pdf_select_layer_config(ctx, pdoc, config);
1969	
1970		while (*lc)
1971		{
1972			int item;
1973	
1974			/* Skip over the last number we read (in the fz_atoi) */
1975			while (*lc >= '0' && *lc <= '9')
1976				lc++;
1977			while (iswhite(*lc))
1978				lc++;
1979			if (*lc != ',')
1980				break;
1981			lc++;
1982			while (iswhite(*lc))
1983				lc++;
1984			if (*lc < '0' || *lc > '9')
1985			{
1986				fprintf(stderr, "Expected a number for UI item to toggle\n");
1987				return;
1988			}
1989			item = fz_atoi(lc);
1990			pdf_toggle_layer_config_ui(ctx, pdoc, item);
1991		}
1992	
1993		/* Now list the final state of the config */
1994		fprintf(stderr, "Layer Config %d:\n", config);
1995		name = pdf_layer_config_name(ctx, pdoc, config);
1996		if (name)
1997			fprintf(stderr, " Name=\"%s\"", name);
1998		creator = pdf_layer_config_creator(ctx, pdoc, config);
1999		if (creator)
2000			fprintf(stderr, " Creator=\"%s\"", creator);
2001		fprintf(stderr, "\n");
2002		n = pdf_count_layer_config_ui(ctx, pdoc);
2003		for (j = 0; j < n; j++)
2004		{
2005			pdf_layer_config_ui ui;
2006	
2007			pdf_layer_config_ui_info(ctx, pdoc, j, &ui);
2008			fprintf(stderr, "%s%d: ", j < 10 ? " " : "", j);
2009			while (ui.depth > 0)
2010			{
2011				ui.depth--;
2012				fprintf(stderr, "  ");
2013			}
2014			if (ui.type == PDF_LAYER_UI_CHECKBOX)
2015				fprintf(stderr, " [%c] ", ui.selected ? 'x' : ' ');
2016			else if (ui.type == PDF_LAYER_UI_RADIOBOX)
2017				fprintf(stderr, " (%c) ", ui.selected ? 'x' : ' ');
2018			if (ui.text)
2019				fprintf(stderr, "%s", ui.text);
2020			if (ui.type != PDF_LAYER_UI_LABEL && ui.locked)
2021				fprintf(stderr, " <locked>");
2022			fprintf(stderr, "\n");
2023		}
2024	#endif
2025	}
