2027	static int create_accel_path(fz_context *ctx, char outname[], size_t len, int create, const char *absname, ...)
2028	{
2029		va_list args;
2030		char *s = outname;
2031		size_t z, remain = len;
2032		char *arg;
2033	
2034		va_start(args, absname);
2035	
2036		while ((arg = va_arg(args, char *)) != NULL)
2037		{
2038			z = fz_snprintf(s, remain, "%s", arg);
2039			if (z+1 > remain)
2040				goto fail; /* won't fit */
2041	
2042			if (create)
2043				(void) fz_mkdir(outname);
2044			if (!fz_is_directory(ctx, outname))
2045				goto fail; /* directory creation failed, or that dir doesn't exist! */
2046	#ifdef _WIN32
2047			s[z] = '\\';
2048	#else
2049			s[z] = '/';
2050	#endif
2051			s[z+1] = 0;
2052			s += z+1;
2053			remain -= z+1;
2054		}
2055	
2056		if (fz_snprintf(s, remain, "%s.accel", absname) >= remain)
2057			goto fail; /* won't fit */
2058	
2059		va_end(args);
2060	
2061		return 1;
2062	
2063	fail:
2064		va_end(args);
2065	
2066		return 0;
2067	}
