2069	static int convert_to_accel_path(fz_context *ctx, char outname[], char *absname, size_t len, int create)
2070	{
2071		char *tmpdir;
2072		char *s;
2073	
2074		if (absname[0] == '/' || absname[0] == '\\')
2075			++absname;
2076	
2077		s = absname;
2078		while (*s) {
2079			if (*s == '/' || *s == '\\' || *s == ':')
2080				*s = '%';
2081			++s;
2082		}
2083	
2084	#ifdef _WIN32
2085		tmpdir = getenv("USERPROFILE");
2086		if (tmpdir && create_accel_path(ctx, outname, len, create, absname, tmpdir, ".config", "mupdf", NULL))
2087			return 1; /* OK! */
2088		/* TEMP and TMP are user-specific on modern windows. */
2089		tmpdir = getenv("TEMP");
2090		if (tmpdir && create_accel_path(ctx, outname, len, create, absname, tmpdir, "mupdf", NULL))
2091			return 1; /* OK! */
2092		tmpdir = getenv("TMP");
2093		if (tmpdir && create_accel_path(ctx, outname, len, create, absname, tmpdir, "mupdf", NULL))
2094			return 1; /* OK! */
2095	#else
2096		tmpdir = getenv("XDG_CACHE_HOME");
2097		if (tmpdir && create_accel_path(ctx, outname, len, create, absname, tmpdir, "mupdf", NULL))
2098			return 1; /* OK! */
2099		tmpdir = getenv("HOME");
2100		if (tmpdir && create_accel_path(ctx, outname, len, create, absname, tmpdir, ".cache", "mupdf", NULL))
2101			return 1; /* OK! */
2102	#endif
2103		return 0; /* Fail */
2104	}
