2106	static int get_accelerator_filename(fz_context *ctx, char outname[], size_t len, const char *fname, int create)
2107	{
2108		char absname[PATH_MAX];
2109		if (!fz_realpath(fname, absname))
2110			return 0;
2111		if (!convert_to_accel_path(ctx, outname, absname, len, create))
2112			return 0;
2113		return 1;
2114	}
